<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Google Trust Services</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: 'Google Sans', Roboto, Arial, sans-serif;
            color: #202124;
            background-color: #fff;
            line-height: 1.6;
        }

        /* Header */
        .header {
            display: flex;
            align-items: center;
            padding: 0 24px;
            height: 48px;
            background: #fff;
            border-bottom: 1px solid #e0e0e0;
            position: sticky;
            top: 0;
            z-index: 100;
        }

        .logo {
            display: flex;
            align-items: center;
            margin-right: 32px;
        }

        .logo-text {
            font-size: 18px;
            color: #5f6368;
            font-weight: 400;
        }

        .google-text {
            color: #202124;
        }

        .nav {
            display: flex;
            align-items: center;
            gap: 8px;
        }

        .nav a {
            text-decoration: none;
            color: #5f6368;
            font-size: 14px;
            padding: 12px 16px;
            position: relative;
        }

        .nav a:hover {
            color: #202124;
        }

        .nav a.active {
            color: #1a73e8;
        }

        .nav a.active::after {
            content: '';
            position: absolute;
            bottom: -1px;
            left: 16px;
            right: 16px;
            height: 3px;
            background: #1a73e8;
            border-radius: 3px 3px 0 0;
        }

        /* Hero Section */
        .hero {
            text-align: center;
            padding: 60px 24px 40px;
            max-width: 800px;
            margin: 0 auto;
        }

        .hero h1 {
            font-size: 44px;
            font-weight: 400;
            color: #202124;
            margin-bottom: 20px;
        }

        .hero p {
            font-size: 18px;
            color: #5f6368;
            line-height: 1.6;
        }

        /* Announcement Box */
        .announcement {
            max-width: 700px;
            margin: 30px auto 50px;
            padding: 28px 32px;
            background: #e8f0fe;
            border-radius: 8px;
            text-align: center;
        }

        .announcement p {
            font-size: 16px;
            color: #202124;
            line-height: 1.7;
        }

        .announcement a {
            color: #1a73e8;
            text-decoration: none;
        }

        .announcement a:hover {
            text-decoration: underline;
        }

        /* Main Content */
        .main-content {
            max-width: 900px;
            margin: 0 auto;
            padding: 0 24px 60px;
        }

        .section-title {
            font-size: 32px;
            font-weight: 400;
            color: #202124;
            margin-bottom: 20px;
        }

        .section-text {
            font-size: 16px;
            color: #5f6368;
            line-height: 1.7;
            margin-bottom: 40px;
            max-width: 700px;
        }

        /* Features Grid */
        .features-grid {
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 40px 60px;
            margin-top: 20px;
        }

        .feature-item {
            padding: 20px 0;
        }

        .feature-item h3 {
            font-size: 22px;
            font-weight: 400;
            color: #202124;
            margin-bottom: 16px;
        }

        .feature-item p {
            font-size: 14px;
            color: #5f6368;
            line-height: 1.7;
        }

        .feature-item.compliance {
            display: grid;
            grid-template-columns: 1fr auto;
            gap: 16px;
        }

        .feature-item.compliance .feature-text {
            grid-column: 1;
        }

        .feature-images {
            display: flex;
            gap: 12px;
            align-items: flex-start;
            grid-column: 2;
            grid-row: 2;
        }

        .feature-img-placeholder {
            width: 56px;
            height: 56px;
            background: linear-gradient(135deg, #e0e0e0 0%, #c0c0c0 100%);
            border-radius: 4px;
        }

        /* Divider */
        .divider {
            border: none;
            border-top: 1px solid #e0e0e0;
            margin: 40px 0;
        }

        /* Info Section */
        .info-section {
            margin-top: 40px;
        }

        .info-section .section-title {
            margin-bottom: 16px;
        }

        .info-section .section-text {
            margin-bottom: 12px;
        }

        .info-link {
            color: #1a73e8;
            text-decoration: none;
            font-size: 14px;
            display: inline-block;
            margin-top: 8px;
        }

        .info-link:hover {
            text-decoration: underline;
        }

        .faq-section {
            margin-top: 50px;
        }

        .faq-section .section-text {
            margin-bottom: 8px;
        }

        .status-section {
            margin-top: 30px;
        }

        .status-section .section-text {
            margin-bottom: 8px;
        }

        /* Cookie Banner */
        .cookie-banner {
            position: fixed;
            bottom: 0;
            left: 0;
            right: 0;
            background: #fff;
            border-top: 1px solid #e0e0e0;
            padding: 16px 24px;
            display: flex;
            align-items: center;
            justify-content: space-between;
            z-index: 200;
            box-shadow: 0 -2px 8px rgba(0, 0, 0, 0.1);
        }

        .cookie-text {
            font-size: 12px;
            color: #5f6368;
            flex: 1;
        }

        .cookie-actions {
            display: flex;
            align-items: center;
            gap: 16px;
            margin-left: 24px;
        }

        .cookie-actions a {
            color: #1a73e8;
            text-decoration: none;
            font-size: 14px;
        }

        .cookie-actions a:hover {
            text-decoration: underline;
        }

        .cookie-btn {
            background: #1a73e8;
            color: #fff;
            border: none;
            padding: 10px 20px;
            border-radius: 4px;
            font-size: 14px;
            cursor: pointer;
        }

        .cookie-btn:hover {
            background: #1765cc;
        }

        /* Footer */
        .footer {
            background: #f8f9fa;
